import React from 'react'

function Merch(props) {
   const{_id, name, price, description} = props.merchandise;
  return (
    <div>
      <h1>Merchandise</h1>
      <p>Name: {name}</p>
      <p>Price: ${price.toFixed(2)}</p>
      <p>Description: {description}</p>
      <button>Edit</button>
      <button>Delete</button>
    </div>
  )
}

export default Merch
